import numpy as np
from typing import List, Dict, Optional

class SimpleQuantumModelChecker:
    """
    A simple model checker for quantum systems.
    """

    def __init__(self, n_qubits: int):
        self.n_qubits = n_qubits
        self.dim = 2**n_qubits
        self.transitions: List[Dict] = []

    def add_transition(self, name: str, operator: np.ndarray):
        """Add a named transition."""
        self.transitions.append({'name': name, 'operator': np.array(operator, dtype=complex)})

    def states_equivalent(self, s1: np.ndarray, s2: np.ndarray, 
                         tol: float = 1e-6) -> bool:
        """Check if states are equivalent up to global phase."""
        # Find first significant element
        for i in range(len(s1)):
            if np.abs(s1[i]) > tol:
                if np.abs(s2[i]) < tol:
                    return False
                phase = s2[i] / s1[i]
                return np.allclose(s1 * phase, s2, atol=tol)
        return np.allclose(s1, s2, atol=tol)

    def _satisfies_predicate(self, state: np.ndarray, predicate: np.ndarray,
                             tol: float = 1e-6) -> bool:
        """Check if state satisfies predicate (projector)."""
        projected = predicate @ state
        return np.allclose(projected, state, atol=tol)

    def _state_visited(self, state: np.ndarray, visited: List, tol: float = 1e-6) -> bool:
        """Check if state already in visited list."""
        for v in visited:
            if self.states_equivalent(state, v, tol):
                return True
        return False

    def check_reachability(self, 
                           initial: np.ndarray,
                           target_predicate: np.ndarray,
                           max_depth: int = 5) -> Dict:
        """Check if target predicate is reachable."""
        initial = np.array(initial, dtype=complex)
        visited = []
        queue = [(initial, [])]  # (state, path)

        while queue:
            state, path = queue.pop(0)

            # Check target
            if self._satisfies_predicate(state, target_predicate):
                return {'reachable': True, 'path': path, 'depth': len(path)}

            # Skip if visited
            if self._state_visited(state, visited):
                continue
            visited.append(state.copy())

            # Check depth limit
            if len(path) >= max_depth:
                continue

            # Explore successors
            for trans in self.transitions:
                next_state = trans['operator'] @ state
                next_state = next_state / np.linalg.norm(next_state)
                queue.append((next_state, path + [trans['name']]))

        return {'reachable': False, 'explored': len(visited)}

    def check_invariant(self,
                        initial: np.ndarray,
                        invariant: np.ndarray,
                        max_depth: int = 5) -> Dict:
        """Check if invariant holds for all reachable states."""
        initial = np.array(initial, dtype=complex)
        visited = []
        queue = [(initial, [])]

        while queue:
            state, path = queue.pop(0)

            # Check invariant
            if not self._satisfies_predicate(state, invariant):
                return {'holds': False, 'counterexample': path}

            if self._state_visited(state, visited):
                continue
            visited.append(state.copy())

            if len(path) >= max_depth:
                continue

            for trans in self.transitions:
                next_state = trans['operator'] @ state
                next_state = next_state / np.linalg.norm(next_state)
                queue.append((next_state, path + [trans['name']]))

        return {'holds': True, 'explored': len(visited)}

# Test
H = np.array([[1, 1], [1, -1]], dtype=complex) / np.sqrt(2)
X = np.array([[0, 1], [1, 0]], dtype=complex)

checker = SimpleQuantumModelChecker(n_qubits=1)
checker.add_transition('H', H)
checker.add_transition('X', X)

state_0 = np.array([1, 0], dtype=complex)
P1 = np.array([[0, 0], [0, 1]], dtype=complex)

result = checker.check_reachability(state_0, P1, max_depth=3)
print(f"Can reach |1> from |0>: {result['reachable']}")
if result['reachable']:
    print(f"Path: {result['path']}")
